// 変数の宣言
var x = 5;
let y = 6;
const z = 7;
console.log(x, y, z); // 予想される出力: 5 6 7

// 変数の再代入
var x = 5;
x = 10;
let y = 6;
y = 12;
const z = 7;
// z = 14; // TypeErrorが発生します。
console.log(x, y, z); // 予想される出力: 10 12 7

// 変数のスコープ
function testVar() {
  var x = 5;
  if(true) {
    var x = 10;
    console.log(x); // 予想される出力: 10
  }
  console.log(x); // 予想される出力: 10
}

function testLet() {
  let y = 5;
  if(true) {
    let y = 10;
    console.log(y); // 予想される出力: 10
  }
  console.log(y); // 予想される出力: 5
}

testVar();
testLet();

// 変数と定数の宣言
let variable = 'I can be changed';
variable = 'See, I have changed';

const constant = 'I cannot be changed';
// constant = 'Try changing me'; // TypeErrorが発生します。
console.log(variable); // 予想される出力: 'See, I have changed'
console.log(constant); // 予想される出力: 'I cannot be changed'

// 正しい変数名
let _variable;
let $variable;
let variable123;

// 間違った変数名
// let 123variable; // 数字から始まる変数名は無効です。
// let var; // 'var'は予約語なので変数名として使用できません。

// 推奨される命名規約
let myVariable;

// 未定義の変数
let x;
console.log(x); // 予想される出力: undefined

// 'Undefined'と'Null'
let undefinedVariable;
let nullVariable = null;
console.log(undefinedVariable); // 予想される出力: undefined
console.log(nullVariable); // 予想される出力: null

// グローバル変数とローカル変数
let globalVariable = 'I am global!'; // これはグローバル変数です。

function testFunction() {
  let localVariable = 'I am local!'; // これはローカル変数です。
  console.log(globalVariable); // 予想される出力: 'I am global!'
  console.log(localVariable); // 予想される出力: 'I am local!'
}

testFunction();
console.log(globalVariable); // 予想される出力: 'I am global!'
// console.log(localVariable); // Error: localVariable is not defined

// 変数の巻き上げ
console.log(myVariable); // 予想される出力: undefined
var myVariable = 'Hello, world!';
console.log(myVariable); // 予想される出力: 'Hello, world!'

// let and const do not hoist
// console.log(myLetVariable); // Error: Cannot access 'myLetVariable' before initialization
let myLetVariable = 'Hello, world!';

// ブロックスコープ
{
  let blockScoped = 'I am block scoped';
  console.log(blockScoped); // 予想される出力: 'I am block scoped'
}
// console.log(blockScoped); // Error: blockScoped is not defined

// 関数スコープ
function testFunction() {
  var functionScoped = 'I am function scoped';
  console.log(functionScoped); // 予想される出力: 'I am function scoped'
}
testFunction();
// console.log(functionScoped); // Error: functionScoped is not defined

// const変数の定義
const myConst = 'Hello, world!';
// myConst = 'Try to reassign'; // Error: Assignment to constant variable.

// const変数にオブジェクトを代入
const myObj = { greeting: 'Hello, world!' };
console.log(myObj.greeting); // 予想される出力: 'Hello, world!'

// myObj = { greeting: 'Try to reassign' }; // Error: Assignment to constant variable.

// しかし、オブジェクト内部の値は変更できます。
myObj.greeting = 'Hello, OpenAI!';
console.log(myObj.greeting); // 予想される出力: 'Hello, OpenAI!'

// varでの再宣言
var myVar = 'Hello, world!';
var myVar = 'Hello, OpenAI!';
console.log(myVar); // 予想される出力: 'Hello, OpenAI!'

// letでの再宣言
let myLet = 'Hello, world!';
// let myLet = 'Hello, OpenAI!'; // Error: Identifier 'myLet' has already been declared

// constでの再宣言
const myConst = 'Hello, world!';
// const myConst = 'Hello, OpenAI!'; // Error: Identifier 'myConst' has already been declared

// 正しい変数名
var $myVar = 'Hello, world!';
let _myVar2 = 'Hello, OpenAI!';
const myVar3 = 'Hello, GPT-4!';

// 間違った変数名
// var 2myVar; // Error: Unexpected number
// let my-var; // Error: Unexpected token -
// const let; // Error: let is a reserved identifier

// undefined変数
let myUndefined;
console.log(myUndefined); // 予想される出力: undefined

// null変数
let myNull = null;
console.log(myNull); // 予想される出力: null

// constで定義、値が変わらない
const myConst = 'Hello, world!';

// letで定義、値が変わる
